// // This module implements a 4-bit shift register with parallel load capability. When parallel_load is deasserted, the module loads a 4-bit input value into the shift register. On each rising edge of the clock, if parallel_load is asserted, the shift register circularly shifts its bits to the right, with the least significant bit wrapped around to the most significant bit position.
module top_module(
    input clk,
    input parallel_load,
    input [3:0] in,
    output reg out
);reg [3:0] shift_reg;

always @(posedge clk) begin
    if (parallel_load) begin
        shift_reg <= in;
    end else begin
        shift_reg <= {shift_reg[2:0], shift_reg[3]};
    end
end

assign out = shift_reg[0];

endmodule
